import{_ as e}from"./chunks/gongan.Co6hjsaP.js";import{_ as r,o as a,c as n,ae as o}from"./chunks/framework.Bn0jkBmj.js";const h=JSON.parse('{"title":"回答家长在使用舒心婴语APP时常见问题","description":"这款宝宝哭声翻译器使用非常简单，只要用手机录制宝宝12秒哭声，AI 就会给出宝宝所 cry 的内容，同步给出护理指导，后期会根据父母的提问整理《宝宝哭声翻译使用手册》。","frontmatter":{"layout":"page","title":"回答家长在使用舒心婴语APP时常见问题","description":"这款宝宝哭声翻译器使用非常简单，只要用手机录制宝宝12秒哭声，AI 就会给出宝宝所 cry 的内容，同步给出护理指导，后期会根据父母的提问整理《宝宝哭声翻译使用手册》。"},"headers":[],"relativePath":"wenda.md","filePath":"wenda.md"}'),i={name:"wenda.md"};function p(s,t,d,l,c,g){return a(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="💡-常见问题解答-faq" tabindex="-1">💡 常见问题解答 (FAQ) <a class="header-anchor" href="#💡-常见问题解答-faq" aria-label="Permalink to &quot;💡 常见问题解答 (FAQ)&quot;">​</a></h1><p><strong>Q1：舒心婴语 AI 测得准吗？</strong> A：目前第一版 AI 模型的准确率稳定在 73% 左右。婴儿哭声差异极大，且受环境噪音影响，因此 AI 结果<strong>仅供参考排查，绝不能替代医疗诊断</strong>。如果宝宝伴有发烧、呕吐等生理病症，请立即就医。</p><p><strong>Q2：每天有几次免费机会？用完了怎么办？</strong> A：为了防止恶意滥用，新注册用户每天享有 3 次免费 AI 分析额度，足够应对日常突发状况。如果次数用完或需要更深度的帮助，您可以升级 VIP 会员，或购买我们的“专家人工辨听”服务。</p><p><strong>Q3：我的录音会被泄露吗？</strong> A：绝对不会。我们采用阿里云企业级服务器加密传输。录音仅用于瞬时 AI 运算，完成分析后系统会自动销毁您的录音原文件（除非您主动授权我们用于模型训练）。</p><p><strong>Q4：我是苹果手机，怎么下载？</strong> A：目前 iOS 苹果版正在紧锣密鼓地开发中。现阶段仅支持安卓系统手机下载使用。</p><p><br><br><br></p><div style="border-top:1px solid var(--vp-c-divider);padding:12px 0;text-align:center;font-size:10px;line-height:2;color:var(--vp-c-text-2);margin-top:40px;width:100%;"><div> ICP备案号： <a href="https://beian.miit.gov.cn" target="_blank" rel="noopener" style="color:var(--vp-c-brand);text-decoration:none;">ICP2025073122</a></div><div><img src="'+e+'" alt="舒心婴语 APP 备案号" style="width:12px;height:12px;vertical-align:-2px;margin-right:4px;display:inline-block;"> 网站联网备案号： <a href="https://beian.mps.gov.cn" target="_blank" rel="noopener" style="color:var(--vp-c-brand);text-decoration:none;">赣公网安备36010202000837号</a></div><div style="margin-top:4px;">Copyright © 2025 南昌市东湖区金宝贝职业月嫂中心</div></div>',7)])])}const m=r(i,[["render",p]]);export{h as __pageData,m as default};
